query:
-- Remove the fake phone number customer
DELETE FROM customers WHERE id = 1129 AND phone = '(12) 345-6789';

-- Re-segment unknown customers based on their last visit date
-- Recent: visited within last 6 months (since Sept 2025)
UPDATE customers SET segment = 'recent' WHERE segment = 'unknown' AND lastVisitDate >= '2025-09-01';

-- Lapsed: visited between 6-18 months ago
UPDATE customers SET segment = 'lapsed' WHERE segment = 'unknown' AND lastVisitDate < '2025-09-01' AND lastVisitDate >= '2024-09-01';

-- Keep truly unknown (no visit date or very old) as unknown

